"use client";

import { createClient } from "@/lib/supabase/client";
import { useEffect, useState } from "react";

export default function SettingsClient() {
  const supabase = createClient();
  const [email, setEmail] = useState("");
  const [newEmail, setNewEmail] = useState("");
  const [createdAt, setCreatedAt] = useState("");
  const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const getUser = async () => {
      const {
        data: { user },
      } = await supabase.auth.getUser();
      if (user) {
        setEmail(user.email ?? "");
        setNewEmail(user.email ?? "");
        setCreatedAt(
          new Date(user.created_at).toLocaleDateString("en-US", {
            year: "numeric",
            month: "long",
            day: "numeric",
          })
        );
      }
    };
    getUser();
  }, [supabase.auth]);

  const handleEmailChange = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    const { error } = await supabase.auth.updateUser({ email: newEmail });

    if (error) {
      setMessage({ type: "error", text: error.message });
    } else {
      setMessage({
        type: "success",
        text: "Confirmation email sent. Please check your inbox to verify the change.",
      });
    }
    setLoading(false);
  };

  return (
    <div className="space-y-6 max-w-2xl">
      <div>
        <h1 className="text-2xl font-bold font-display text-white">Settings</h1>
        <p className="text-slate-400 mt-1">Manage your account preferences</p>
      </div>

      {/* Profile Info */}
      <div className="bg-navy-100 border border-slate-800 rounded-xl p-6">
        <h2 className="text-lg font-semibold text-white mb-4">Profile</h2>
        <div className="space-y-4">
          <div>
            <label className="text-sm text-slate-400 block mb-1">Email</label>
            <p className="text-white">{email || "Loading..."}</p>
          </div>
          <div>
            <label className="text-sm text-slate-400 block mb-1">
              Member Since
            </label>
            <p className="text-white">{createdAt || "Loading..."}</p>
          </div>
          <div>
            <label className="text-sm text-slate-400 block mb-1">Plan</label>
            <span className="inline-flex items-center px-2.5 py-0.5 rounded text-xs font-medium bg-cobalt/10 text-cobalt border border-cobalt/20">
              Pro Trader
            </span>
          </div>
        </div>
      </div>

      {/* Change Email Form */}
      <div className="bg-navy-100 border border-slate-800 rounded-xl p-6">
        <h2 className="text-lg font-semibold text-white mb-4">
          Change Email
        </h2>
        <form onSubmit={handleEmailChange} className="space-y-4">
          <div>
            <label
              htmlFor="new-email"
              className="text-sm text-slate-400 block mb-2"
            >
              New Email Address
            </label>
            <input
              id="new-email"
              type="email"
              value={newEmail}
              onChange={(e) => setNewEmail(e.target.value)}
              required
              className="w-full px-4 py-2.5 bg-navy border border-slate-700 rounded-lg text-white placeholder-slate-500 focus:outline-none focus:ring-2 focus:ring-cobalt focus:border-transparent text-sm"
              placeholder="new@email.com"
            />
          </div>
          {message && (
            <div
              className={`text-sm px-4 py-2.5 rounded-lg ${
                message.type === "success"
                  ? "bg-accent/10 text-accent border border-accent/20"
                  : "bg-red-500/10 text-red-400 border border-red-500/20"
              }`}
            >
              {message.text}
            </div>
          )}
          <button
            type="submit"
            disabled={loading || newEmail === email}
            className="px-5 py-2.5 bg-cobalt hover:bg-cobalt-600 disabled:opacity-50 disabled:cursor-not-allowed text-white text-sm font-medium rounded-lg transition-colors"
          >
            {loading ? "Sending..." : "Update Email"}
          </button>
        </form>
      </div>

      {/* Danger Zone */}
      <div className="bg-navy-100 border border-red-500/20 rounded-xl p-6">
        <h2 className="text-lg font-semibold text-red-400 mb-2">
          Danger Zone
        </h2>
        <p className="text-sm text-slate-400 mb-4">
          Permanently delete your account and all associated data. This action
          cannot be undone.
        </p>
        <button className="px-5 py-2.5 bg-red-500/10 hover:bg-red-500/20 text-red-400 text-sm font-medium rounded-lg border border-red-500/20 transition-colors">
          Delete Account
        </button>
      </div>
    </div>
  );
}

export interface User {
  id: string;
  email: string;
  password: string;
  name: string;
  created_at: string;
}

export interface WatchlistItem {
  id: string;
  user_id: string;
  symbol: string;
  name: string;
  added_at: string;
}

export interface Prediction {
  id: string;
  user_id: string;
  ticker: string;
  direction: "bullish" | "bearish" | "neutral";
  confidence: number;
  timestamp: string;
}

import fs from "fs";
import path from "path";
import bcrypt from "bcryptjs";
import type { User, WatchlistItem, Prediction } from "./types";

const DATA_DIR = path.join(process.cwd(), "frontend", "data");

function ensureDataDir() {
  if (!fs.existsSync(DATA_DIR)) {
    fs.mkdirSync(DATA_DIR, { recursive: true });
  }
}

function readJSON<T>(filename: string): T[] {
  ensureDataDir();
  const filePath = path.join(DATA_DIR, filename);
  if (!fs.existsSync(filePath)) {
    fs.writeFileSync(filePath, "[]", "utf-8");
    return [];
  }
  const raw = fs.readFileSync(filePath, "utf-8");
  return JSON.parse(raw) as T[];
}

function writeJSON<T>(filename: string, data: T[]) {
  ensureDataDir();
  const filePath = path.join(DATA_DIR, filename);
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2), "utf-8");
}

function genId(): string {
  return crypto.randomUUID();
}

// ── Users ───────────────────────────────────────────────────────────────────

export function getUsers(): User[] {
  return readJSON<User>("users.json");
}

export async function createUser(
  email: string,
  password: string,
  name: string
): Promise<User> {
  const users = getUsers();
  if (users.find((u) => u.email === email)) {
    throw new Error("User already exists");
  }
  const hashed = await bcrypt.hash(password, 10);
  const user: User = {
    id: genId(),
    email,
    password: hashed,
    name,
    created_at: new Date().toISOString(),
  };
  users.push(user);
  writeJSON("users.json", users);
  return user;
}

export function getUserByEmail(email: string): User | undefined {
  return getUsers().find((u) => u.email === email);
}

export async function verifyPassword(
  email: string,
  password: string
): Promise<User | null> {
  const user = getUserByEmail(email);
  if (!user) return null;
  const valid = await bcrypt.compare(password, user.password);
  return valid ? user : null;
}

// ── Watchlist ───────────────────────────────────────────────────────────────

export function getWatchlist(userId: string): WatchlistItem[] {
  return readJSON<WatchlistItem>("watchlists.json").filter(
    (w) => w.user_id === userId
  );
}

export function addToWatchlist(
  userId: string,
  symbol: string,
  name: string
): WatchlistItem {
  const items = readJSON<WatchlistItem>("watchlists.json");
  if (items.find((w) => w.user_id === userId && w.symbol === symbol)) {
    throw new Error("Ticker already in watchlist");
  }
  const item: WatchlistItem = {
    id: genId(),
    user_id: userId,
    symbol: symbol.toUpperCase(),
    name,
    added_at: new Date().toISOString(),
  };
  items.push(item);
  writeJSON("watchlists.json", items);
  return item;
}

export function removeFromWatchlist(userId: string, ticker: string): boolean {
  const items = readJSON<WatchlistItem>("watchlists.json");
  const filtered = items.filter(
    (w) => !(w.user_id === userId && w.symbol === ticker.toUpperCase())
  );
  if (filtered.length === items.length) return false;
  writeJSON("watchlists.json", filtered);
  return true;
}

// ── Predictions ─────────────────────────────────────────────────────────────

export function getPredictions(userId: string): Prediction[] {
  return readJSON<Prediction>("predictions.json").filter(
    (p) => p.user_id === userId
  );
}

export function addPrediction(
  userId: string,
  prediction: Omit<Prediction, "id" | "user_id">
): Prediction {
  const items = readJSON<Prediction>("predictions.json");
  const pred: Prediction = {
    id: genId(),
    user_id: userId,
    ...prediction,
  };
  items.push(pred);
  writeJSON("predictions.json", items);
  return pred;
}

import { createServerClient } from "@supabase/ssr";
import { cookies } from "next/headers";

export async function auth(): Promise<{ userId: string } | null> {
  const cookieStore = await cookies();
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL || process.env.SUPABASE_URL;
  const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || process.env.SUPABASE_ANON_KEY;

  if (!url || !key) {
    // Fallback: read session from a simple cookie for dev without Supabase
    const sessionCookie = cookieStore.get("goon_session");
    if (sessionCookie) {
      try {
        const session = JSON.parse(sessionCookie.value);
        if (session.userId) return { userId: session.userId };
      } catch {
        // invalid cookie
      }
    }
    return null;
  }

  const supabase = createServerClient(url, key, {
    cookies: {
      getAll() {
        return cookieStore.getAll();
      },
      setAll() {
        // read-only in auth context
      },
    },
  });

  const {
    data: { user },
  } = await supabase.auth.getUser();

  if (!user) return null;
  return { userId: user.id };
}

export function createClient() {
  const url = process.env.NEXT_PUBLIC_SUPABASE_URL || process.env.SUPABASE_URL || "";
  const key = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY || process.env.SUPABASE_ANON_KEY || "";

  if (!url || !key) {
    return null;
  }

  // Dynamic import to avoid crash if @supabase/supabase-js isn't configured
  try {
    // eslint-disable-next-line @typescript-eslint/no-require-imports
    const { createClient: createSupabaseClient } = require("@supabase/supabase-js");
    return createSupabaseClient(url, key);
  } catch {
    return null;
  }
}

/**
 * Seeded prediction engine — returns deterministic results per ticker for demo.
 */

export interface PredictionResult {
  direction: "bullish" | "bearish" | "neutral";
  confidence: number;
  timestamp: string;
}

function seedHash(ticker: string): number {
  let hash = 0;
  for (let i = 0; i < ticker.length; i++) {
    const char = ticker.charCodeAt(i);
    hash = ((hash << 5) - hash + char) | 0;
  }
  return Math.abs(hash);
}

function seededRandom(seed: number): () => number {
  let s = seed % 2147483647;
  if (s <= 0) s += 2147483646;
  return () => {
    s = (s * 16807) % 2147483647;
    return (s - 1) / 2147483646;
  };
}

export function generatePrediction(ticker: string): PredictionResult {
  const seed = seedHash(ticker.toUpperCase());
  const rand = seededRandom(seed);

  const directions: PredictionResult["direction"][] = ["bullish", "bearish", "neutral"];
  const direction = directions[Math.floor(rand() * 3)];
  const confidence = Math.floor(rand() * 66) + 30; // 30–95

  return {
    direction,
    confidence,
    timestamp: new Date().toISOString(),
  };
}

import { NextResponse } from "next/server";
